# Module defining shape classes with inheritance and properties

class Shape:
    """Base class for all shapes"""
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def area(self) -> float:
        return 0.0

    @virtual
    def perimeter(self) -> float:
        return 0.0

    def describe(self) -> str:
        return self.name + " (area=" + str(self.area()) + ", perimeter=" + str(self.perimeter()) + ")"


class Rectangle(Shape):
    """Rectangle shape with width and height"""
    width: float
    height: float

    def __init__(self, name: str, width: float, height: float):
        super().__init__(name)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)


class Square(Rectangle):
    """Square is a special rectangle with equal sides"""

    def __init__(self, name: str, side: float):
        # Call Rectangle's constructor with equal width and height
        super().__init__(name, side, side)


class Circle(Shape):
    """Circle shape with radius"""
    radius: float
    const PI: float = 3.14159

    def __init__(self, name: str, radius: float):
        super().__init__(name)
        self.radius = radius

    @override
    def area(self) -> float:
        return Circle.PI * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * Circle.PI * self.radius

