# Utility functions for shape operations

from shapes import Shape, Rectangle, Circle

def largest_area(shapes: list[Shape]) -> Shape:
    """Find the shape with the largest area"""
    if len(shapes) == 0:
        raise ValueError("Empty list")

    largest: Shape = shapes[0]
    for shape in shapes:
        if shape.area() > largest.area():
            largest = shape
    return largest

def total_perimeter(shapes: list[Shape]) -> float:
    """Calculate total perimeter of all shapes"""
    total: float = 0.0
    for shape in shapes:
        total = total + shape.perimeter()
    return total

def describe_all(shapes: list[Shape]) -> list[str]:
    """Get descriptions of all shapes"""
    descriptions: list[str] = []
    for shape in shapes:
        descriptions.append(shape.describe())
    return descriptions
